import{_ as r,c as s,o as n,a5 as a,j as e,a as t,at as l}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse(`{"title":"2.1b How to Copy Content","description":"Why can't Ctrl+C copy? Learn three efficient ways to copy in OpenCode.","frontmatter":{"title":"2.1b How to Copy Content","subtitle":"Goodbye Ctrl+C Confusion","course":"OpenCode Practical Course","stage":"Phase 2","lesson":"2.1b","duration":"5 min","practice":"5 min","level":"Beginner","description":"Why can't Ctrl+C copy? Learn three efficient ways to copy in OpenCode.","tags":["Copy Paste","Basic Operations","Windows","Mac"],"prerequisite":["2.1 Interface & Operations"]},"headers":[],"relativePath":"en/2-daily/01b-copy-paste.md","filePath":"en/2-daily/01b-copy-paste.md","lastUpdated":1772014034000}`),i={name:"en/2-daily/01b-copy-paste.md"};function d(c,o,h,p,u,b){return n(),s("div",null,[...o[0]||(o[0]=[a('<h1 id="_2-1b-how-to-copy-content" tabindex="-1">2.1b How to Copy Content <a class="header-anchor" href="#_2-1b-how-to-copy-content" aria-label="Permalink to “2.1b How to Copy Content”">​</a></h1><blockquote><p>💡 <strong>First Question from Beginners</strong>: &quot;Why does the program exit when I press Ctrl+C?!&quot;</p></blockquote><h2 id="📝-course-notes" tabindex="-1">📝 Course Notes <a class="header-anchor" href="#📝-course-notes" aria-label="Permalink to “📝 Course Notes”">​</a></h2><p>Key takeaways from this lesson:</p><img src="'+l+'" alt="Copy operations cheat sheet" data-zoom-src="/images/2-daily/01b-copy-paste-notes.jpeg"><hr><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to “What You&#39;ll Learn”">​</a></h2><ul><li>Understand why Ctrl+C doesn&#39;t work for copying</li><li>Master the &quot;magic&quot; of copy-on-selection with your mouse</li><li>Learn to copy AI&#39;s long responses with one keystroke</li><li>Solve text selection issues in Windows terminals</li></ul><hr><h2 id="💥-why-doesn-t-ctrl-c-work" tabindex="-1">💥 Why Doesn&#39;t Ctrl+C Work? <a class="header-anchor" href="#💥-why-doesn-t-ctrl-c-work" aria-label="Permalink to “💥 Why Doesn&#39;t Ctrl+C Work?”">​</a></h2><p>For users accustomed to Word and browsers, this might be the biggest culture shock.</p><p>In the terminal world (the black box where OpenCode runs), <code>Ctrl+C</code> is typically used as an interrupt signal, not a copy shortcut.</p><ul><li><strong>In Word</strong>: <code>Ctrl+C</code> = 📷 <strong>Take a snapshot</strong> (copy content)</li><li><strong>In Terminal</strong>: <code>Ctrl+C</code> = 🛑 <strong>Interrupt</strong></li></ul><p>Therefore, pressing <code>Ctrl+C</code> in OpenCode doesn&#39;t copy the selected content.</p><hr><h2 id="🚀-method-1-mouse-flow-most-intuitive" tabindex="-1">🚀 Method 1: Mouse Flow (Most Intuitive) <a class="header-anchor" href="#🚀-method-1-mouse-flow-most-intuitive" aria-label="Permalink to “🚀 Method 1: Mouse Flow (Most Intuitive)”">​</a></h2><p>This is a &quot;hidden skill&quot; specially designed by OpenCode for modern users, <strong>works on both Windows and Mac</strong>.</p><h3 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to “Steps”">​</a></h3><ol><li><strong>Press and hold the left mouse button</strong>, drag to select the text you want to copy.</li><li><strong>Release the left mouse button</strong>.</li><li><strong>Done!</strong> 🎉</li></ol><p>Yes, you read that right. You don&#39;t need to right-click or press any key. The moment you <strong>release the mouse</strong>, OpenCode automatically copies the selected content to the clipboard and shows <code>Copied to clipboard</code>.</p><hr><h2 id="⌨️-method-2-keyboard-flow-fastest" tabindex="-1">⌨️ Method 2: Keyboard Flow (Fastest) <a class="header-anchor" href="#⌨️-method-2-keyboard-flow-fastest" aria-label="Permalink to “⌨️ Method 2: Keyboard Flow (Fastest)”">​</a></h2><p>When you only want <strong>what the AI just said</strong> (like a big chunk of code), dragging with the mouse is too tedious.</p><h3 id="steps-1" tabindex="-1">Steps <a class="header-anchor" href="#steps-1" aria-label="Permalink to “Steps”">​</a></h3><ol><li>Press the <strong>Leader key</strong> (default is <kbd>Ctrl</kbd>+<kbd>X</kbd>).</li><li>Release all keys.</li><li>Press <kbd>Y</kbd>.</li></ol><p><strong>Memory trick</strong>: <code>Y</code> = <strong>Y</strong>ank (this is programmer slang for &quot;copy&quot;).</p><blockquote><p>Want more shortcuts? Check out <strong><a href="./03-shortcuts.html">2.3 Recommended Shortcuts</a></strong>.</p></blockquote><hr><h2 id="📜-method-3-command-flow-most-complete" tabindex="-1">📜 Method 3: Command Flow (Most Complete) <a class="header-anchor" href="#📜-method-3-command-flow-most-complete" aria-label="Permalink to “📜 Method 3: Command Flow (Most Complete)”">​</a></h2><p>When you want to save <strong>the entire conversation history</strong> (what you said + what the AI said) to share with friends or save to a document.</p><h3 id="steps-2" tabindex="-1">Steps <a class="header-anchor" href="#steps-2" aria-label="Permalink to “Steps”">​</a></h3><ol><li>Type <code>/copy</code> in the input box.</li><li>Press <kbd>Enter</kbd>.</li></ol><p>The entire conversation history will be copied completely.</p><hr><h2 id="🛡️-last-resort-force-system-copy" tabindex="-1">🛡️ Last Resort: Force System Copy <a class="header-anchor" href="#🛡️-last-resort-force-system-copy" aria-label="Permalink to “🛡️ Last Resort: Force System Copy”">​</a></h2><p>If the &quot;magic&quot; above doesn&#39;t work, or you just want to use the native system copy method.</p><table tabindex="0"><thead><tr><th>System</th><th>Operation</th></tr></thead><tbody><tr><td><strong>Mac</strong></td><td>Hold <kbd>Option (⌥)</kbd> + mouse drag select → <kbd>Command</kbd>+<kbd>C</kbd></td></tr><tr><td><strong>Windows</strong> (before v1.1.64)</td><td>Hold <kbd>Shift</kbd> + mouse drag select → <kbd>Right click</kbd> or <kbd>Enter</kbd></td></tr><tr><td><strong>Windows</strong> (v1.1.64+)</td><td>Direct mouse drag select → auto copy or <kbd>Ctrl</kbd>+<kbd>C</kbd></td></tr></tbody></table><p><strong>Use Cases</strong>:</p><ul><li>When OpenCode is frozen and unresponsive</li><li>When you want to precisely copy error messages</li><li>When the terminal window is hijacked by another program</li></ul><hr><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to “Follow Along”">​</a></h2><h3 id="step-1-experience-ctrl-c" tabindex="-1">Step 1: Experience Ctrl+C <a class="header-anchor" href="#step-1-experience-ctrl-c" aria-label="Permalink to “Step 1: Experience Ctrl+C”">​</a></h3><ol><li>Type a few characters in the input box (don&#39;t send it).</li><li>Press <kbd>Ctrl</kbd>+<kbd>C</kbd>.</li><li>Did the input box get cleared? That&#39;s because Ctrl+C was recognized as an interrupt signal.</li></ol><h3 id="step-2-experience-auto-copy" tabindex="-1">Step 2: Experience &quot;Auto Copy&quot; <a class="header-anchor" href="#step-2-experience-auto-copy" aria-label="Permalink to “Step 2: Experience &quot;Auto Copy&quot;”">​</a></h3><ol><li>Let the AI say something (e.g., type <code>hi</code>).</li><li>Use your mouse to select a few words from the AI&#39;s response.</li><li><strong>Release the mouse</strong>.</li><li>Open a notepad and press <code>Ctrl+V</code> to paste.</li><li>Did it work?</li></ol><h3 id="step-3-experience-force-copy" tabindex="-1">Step 3: Experience &quot;Force Copy&quot; <a class="header-anchor" href="#step-3-experience-force-copy" aria-label="Permalink to “Step 3: Experience &quot;Force Copy&quot;”">​</a></h3><ol><li>Go back to OpenCode.</li><li><strong>Mac users</strong>: Hold <kbd>Option</kbd>, <strong>Windows users</strong>: Hold <kbd>Shift</kbd>.</li><li>Drag select some text with your mouse.</li><li>This method bypasses OpenCode and uses the terminal system&#39;s selection function directly.</li></ol><hr><h2 id="🚑-troubleshooting-what-if-garbled-text-appears" tabindex="-1">🚑 Troubleshooting: What If Garbled Text Appears? <a class="header-anchor" href="#🚑-troubleshooting-what-if-garbled-text-appears" aria-label="Permalink to “🚑 Troubleshooting: What If Garbled Text Appears?”">​</a></h2><p><strong>Symptom</strong>: If you&#39;re a Windows user, after pressing <code>Ctrl+C</code> to exit, you might see garbled text like <code>[555;38;16M</code> appearing on screen when you move the mouse.</p><p><strong>Cause</strong>:</p><ul><li>OpenCode enables &quot;mouse tracking mode&quot; on startup.</li><li><code>Ctrl+C</code> on Windows is a forceful termination signal (SIGINT).</li><li>This causes OpenCode to be killed before it can tell the terminal to &quot;disable mouse tracking&quot;.</li><li>The terminal thinks you&#39;re still in the program and keeps sending mouse coordinates to the screen, which appears as garbled text.</li></ul><blockquote><p>🐛 <strong>Known Issue</strong>: As of OpenCode <strong>v1.1.25</strong>, this issue is not fully resolved on Windows. This is a low-level technical limitation, we recommend following the table below.</p></blockquote><p><strong>Solutions</strong>:</p><ol><li><strong>Quick Fix</strong>: Close the current terminal window and reopen it.</li><li><strong>Prevention (Highly Recommended)</strong>: Don&#39;t use <code>Ctrl+C</code> to exit! Use <strong>Ctrl+D</strong> instead.</li></ol><table tabindex="0"><thead><tr><th>Exit Method</th><th>Nature</th><th>Result</th></tr></thead><tbody><tr><td><kbd>Ctrl</kbd>+<kbd>C</kbd></td><td>🔪 <strong>Force Kill</strong></td><td>Prone to mouse garbled text, not recommended</td></tr><tr><td><kbd>Ctrl</kbd>+<kbd>D</kbd></td><td>👋 <strong>Graceful Exit</strong></td><td>Clean exit with automatic cleanup, <strong>recommended</strong></td></tr></tbody></table><blockquote><p><strong>Tip</strong>: <code>Ctrl+D</code> triggers OpenCode&#39;s cleanup logic, ensuring mouse mode is properly disabled.</p></blockquote><hr><h2 id="🎉-good-news-major-windows-experience-improvements-v1-1-64" tabindex="-1">🎉 Good News: Major Windows Experience Improvements (v1.1.64+) <a class="header-anchor" href="#🎉-good-news-major-windows-experience-improvements-v1-1-64" aria-label="Permalink to “🎉 Good News: Major Windows Experience Improvements (v1.1.64+)”">​</a></h2><blockquote><p>🪟 <strong>Windows Exclusive</strong>: If you&#39;re using <strong>OpenCode v1.1.64 or later</strong>, congratulations!</p></blockquote><p>Starting from v1.1.64, the text selection experience on Windows has been greatly improved:</p><table tabindex="0"><thead><tr><th>Improvement</th><th>Before</th><th>Now</th></tr></thead><tbody><tr><td>Mouse selection</td><td>Required holding Shift</td><td>Direct drag select works</td></tr><tr><td>Ctrl+C copy</td><td>Not supported</td><td>Supports manual copy of selected content</td></tr></tbody></table><p><strong>Now Windows users can</strong>:</p><ul><li>Select text directly with the mouse like a normal text editor</li><li>Press <code>Ctrl+C</code> to manually copy after selection (if auto copy doesn&#39;t trigger)</li></ul><blockquote><p>📌 <strong>Version Check</strong>: Type <code>/version</code> to check your OpenCode version.</p></blockquote><hr><h2 id="📚-further-reading" tabindex="-1">📚 Further Reading <a class="header-anchor" href="#📚-further-reading" aria-label="Permalink to “📚 Further Reading”">​</a></h2><ul><li><p>Want to master more shortcuts? 👉 <strong><a href="./03-shortcuts.html">2.3 Recommended Shortcuts</a></strong></p></li><li><p>Want to customize shortcuts (like changing Ctrl+C back)? 👉 <strong><a href="./../5-advanced/06b-keybinds.html">5.6b Shortcut Customization</a></strong></p></li></ul><hr><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to “Next Lesson Preview”">​</a></h2><blockquote><p>Next lesson: <strong><a href="./01c-basic-tools.html">AI&#39;s Basic Tools</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>What are the 6 basic tools AI has and what each does</li><li>The &quot;read before write&quot; rule and edit&#39;s smart matching</li><li>Why you shouldn&#39;t let AI use bash for file operations</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to “Appendix: Source Code Reference”">​</a></h2>',73),e("details",null,[e("summary",null,[e("strong",null,"Click to expand source code locations")]),e("blockquote",null,[e("p",null,"Last updated: 2026-02-14 (v1.1.64)")]),e("p",null,`OpenCode's "copy on mouse release" logic is not a terminal default behavior, but an advanced feature written in code:`),e("table",{tabindex:"0"},[e("thead",null,[e("tr",null,[e("th",null,"Feature"),e("th",null,"File Path"),e("th",null,"Key Logic")])]),e("tbody",null,[e("tr",null,[e("td",null,"Mouse copy logic"),e("td",null,[e("a",{href:"https://github.com/anomalyco/opencode/blob/dev/packages/opencode/src/cli/cmd/tui/app.tsx",target:"_blank",rel:"noreferrer"},[e("code",null,"src/cli/cmd/tui/app.tsx")])]),e("td",null,[e("code",null,"onMouseUp"),t(" event listener")])]),e("tr",null,[e("td",null,"Clipboard utility"),e("td",null,[e("a",{href:"https://github.com/anomalyco/opencode/blob/dev/packages/opencode/src/cli/cmd/tui/util/clipboard.ts",target:"_blank",rel:"noreferrer"},[e("code",null,"src/cli/cmd/tui/util/clipboard.ts")])]),e("td",null,"Cross-platform clipboard support")]),e("tr",null,[e("td",null,"Windows selection improvement (v1.1.64)"),e("td",null,[t("Search keywords "),e("code",null,"windows"),t(", "),e("code",null,"win32"),t(", "),e("code",null,"selection")]),e("td",null,[e("code",null,"packages/opencode/src/")])])])]),e("p",null,[e("strong",null,"Source code search command"),t(":")]),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},'grep -rn "windows\\|win32\\|selection" packages/opencode/src/')])]),e("p",null,[e("strong",null,[t("Core code snippet ("),e("code",null,"app.tsx"),t(")")]),t(":")]),e("div",{class:"language-typescript"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"typescript"),e("pre",null,[e("code",{"v-pre":""},`// When mouse is released
onMouseUp={async () => {
  // 1. Get selected text
  const text = renderer.getSelection()?.getSelectedText()
  if (text && text.length > 0) {
    // 2. Call clipboard API to copy
    await Clipboard.copy(text)
    // 3. Notify user
    toast.show({ message: "Copied to clipboard" })
    // 4. Clear selection state
    renderer.clearSelection()
  }
}}`)])])],-1)])])}const y=r(i,[["render",d]]);export{m as __pageData,y as default};
